"use strict";const t=t=>`${t.getFullYear()}-${String(t.getMonth()+1).padStart(2,"0")}-${String(t.getDate()).padStart(2,"0")}`;exports.formatDateTime=t=>t?t.replace("T"," ").substring(0,19):"",exports.formatTime=t=>t.substring(0,5),exports.generateDateList=(e=7)=>{const r=[],a=["日","一","二","三","四","五","六"],s=new Date;for(let n=0;n<e;n++){const e=new Date(s);e.setDate(s.getDate()+n),r.push({value:t(e),week:0===n?"今天":"周"+a[e.getDay()],day:e.getDate()})}return r},exports.isVenueOpen=t=>{if(1!==t.status)return!1;const e=new Date,r=`${String(e.getHours()).padStart(2,"0")}:${String(e.getMinutes()).padStart(2,"0")}`;return r>=t.openTime&&r<=t.closeTime};
